mapper.update:
UPDATE posts
SET title = #{title},
    body  = #{body},
    tag   = #{tag}
WHERE id = #{id}
  AND deleted_at IS NULL

UPDATE posts
SET deleted_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE posts
SET deleted_at = NULL
WHERE id = #{id}

UPDATE posts
SET votes = votes + #{direction}
WHERE id = #{id}
  AND deleted_at IS NULL

mapper.select:
SELECT *
FROM posts
WHERE author = #{username}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{skip}

SELECT COUNT(*)
FROM posts
WHERE author = #{username}
